package main

func main() {
	ch := make(chan int, 10) // 带缓冲 channel
	done := make(chan struct{})

	go func() {
		for v := range ch {
			_ = v // 处理数据
		}
		done <- struct{}{}
	}()

	for i := 0; i < 5; i++ {
		ch <- i
	}
	close(ch)
	<-done
}
